export function randomId(prefix = 'mantine-'): string {
  return `${prefix}${Math.random().toString(36).slice(2, 11)}`;
}

export function* mapIterator<T, U>(iter: Iterable<T>, mapFn: (x: T) => U): Generator<U, void, unknown> {
    for (const x of iter) {
        yield mapFn(x);
    }
}

export interface StoreApi<T> {
  setState: SetStateInternal<T>
  getState: () => T
  getInitialState: () => T
  subscribe: (listener: (state: T, prevState: T) => void) => () => void
}

export function base64ByteLength(data: string): number {
  if (!data)
    return 0;
  const padding = (data[data.length - 2] === '=') ? 2 : ((data[data.length - 1] === '=') ? 1 : 0);
  return Math.max(0, Math.floor(data.length * 3 / 4) - padding);
}

export function isObject(obj: any): obj is NonNullable<object> {
  return typeof obj === 'object' && obj !== null;
}

export function isError(obj: any): obj is Error {
  return obj instanceof Error || (obj && Object.getPrototypeOf(obj)?.name === 'Error');
}

function isWordChar(ch: number) {
    return isUpperCaseLetter(ch) || isLowerCaseLetter(ch) || isDigit(ch) || ch === CharacterCodes._ || ch === CharacterCodes.$;
}

export interface StateStorage<R = unknown> {
  getItem: (name: string) => string | null | Promise<string | null>
  setItem: (name: string, value: string) => R
  removeItem: (name: string) => R
}

export const mssqlPreparedStatement = (sql: Sql) => {
  return sql.strings.reduce((acc, str, idx) => `${acc}@P${idx}${str}`)
}

export function printConfigWarnings(warnings: string[]) {
  if (warnings && warnings.length > 0) {
    const message = warnings.map((warning) => `${yellow('warn')} ${warning}`).join('\n')
    console.warn(message)
  }
}

export const normalizeArrays = <T>(array: T[] | T | undefined): T[] => {
  if (Array.isArray(array)) {
    return array;
  }
  return array ? [array] : [];
};

type ContentTypeHandler = {
  isMatch: (opts: Request) => boolean;
  parse: (opts: GetRequestInfoOptions) => Promise<TRPCRequestInfo>;
};

if (diag.code && COMPILER_ERRORS_WITH_GUIDES.has(ngErrorCode(diag.code))) {
  return {
    ...diag,
    messageText:
      diag.messageText +
      `. Find more at ${ERROR_DETAILS_PAGE_BASE_URL}/NG${ngErrorCode(diag.code)}`,
  };
}

for (let i = -YEAR_RANGE; i <= YEAR_RANGE; i++) {
  const date = state.focusedDate.add({ years: i });

  years.push({
    value: date,
    formatted: formatter.format(date.toDate(state.timeZone)),
  });
}

if (sep !== '/' && sep !== ':' && sep !== '') {
  throw new UnscopedValidationError(lit`InvalidResourcePathSeparator`, 'resourcePathSep may only be ":", "/" or an empty string');
}

if (!hasName) {
  arnFormat = ArnFormat.NO_RESOURCE_NAME;
} else {
  arnFormat = sepIfToken === '/' ? ArnFormat.SLASH_RESOURCE_NAME : ArnFormat.COLON_RESOURCE_NAME;
}

if (pkgInfo.error?.code === "E404") {
  warn(`Received 404 for npm info ${pc.cyan(`"${packageJson.name}"`)}`);
  return { published: false, pkgInfo: {} };
}

if (month === 2) {
  if ((year % 4 === 0 && year % 100 !== 0) || year % 400 === 0) {
    return day <= 29;
  }
  return day <= 28;
}

if (authDef && !(userDef && passDef)) {
  authDef = Buffer.from(authDef, "base64").toString();
  authDef = authDef.split(":");
  userDef = authDef.shift();
  passDef = authDef.join(":");
}

if (isObject(item) && !Array.isArray(item) && key in item) {
  const itemValue = item[key]
  if (itemValue !== null && itemValue !== undefined) {
    values.push(itemValue)
  }
}

if (serial) {
  await socket.write(encodeMessage(`host:transport:${serial}`));
  const status = await socket.read(4);
  assert(status.toString() === 'OKAY', status.toString());
}

if (
    !type1.priv.tupleTypeArgs ||
