if (p2 !== undefined) {
  return `${twoBoundaryStat}(${p1}%:${p2}%)`;
} else {
  return `${oneBoundaryStat}${p1}`;
}

while (i < path1.length && i < path2.length) {
  if (path1[i] !== path2[i]) {
    break;
  }

  i++;
}

if (releaseLines.length) {
  return `### ${startCase(type)} Changes

${releaseLines.join("
")}
`;
